import time
import logging
import os
from watchdog.observers import Observer
from watchdog.events import FileSystemEventHandler

logging.basicConfig(level=logging.INFO,
                    format='%(asctime)s - %(message)s',
                    datefmt='%Y-%m-%d %H:%M:%S')

class MyHandler(FileSystemEventHandler):
    def on_created(self, event):
        logging.info(f"Oluşturuldu: {event.src_path}")

    def on_deleted(self, event):
        logging.info(f"Silindi: {event.src_path}")

    def on_modified(self, event):
        if not event.is_directory:
            logging.info(f"Değiştirildi: {event.src_path}")

    def on_moved(self, event):
        logging.info(f"Taşındı/Yeniden Adlandırıldı: {event.src_path} -> {event.dest_path}")

if __name__ == "__main__":
    path_to_watch = os.getcwd() 
    # İzlemek istediğiniz dizin yolunu buraya yazın.
    # Örneğin: path_to_watch = "/Users/kullaniciadi/belgeler"

    event_handler = MyHandler()
    observer = Observer()
    observer.schedule(event_handler, path_to_watch, recursive=True)
    observer.start()
    try:
        while True:
            time.sleep(1)
    except KeyboardInterrupt:
        observer.stop()
    observer.join()
